// Generate enrichment job request with signal source context
const weekDate = new Date().toISOString().split('T')[0];

return [{
  json: {
    weekDate,
    idempotencyKey: `sales-enrichment:weekly:${weekDate}`,
    prompt: `Run prospect enrichment cycle with signal detection for all enabled verticals.\n\n**IMPORTANT**: Read config.json at the runner working directory to get the verticals and salesMarketing configuration.\n\nFor each enabled vertical:\n1. Query Attio for prospects in that vertical with Priority=High or lead_score >= 40 and incomplete data\n2. Dispatch sales-researcher to enrich with decision-maker contacts, company size, CE status\n3. Have sales-researcher check the signal sources defined in the vertical's signalSources config (focus on wednesday_1000 schedule sources)\n4. Re-score enriched prospects using the vertical's scoring matrix\n5. Check for MQL promotion: lead_score >= salesMarketing.mqlThreshold AND signal within salesMarketing.mqlSignalWindowDays\n6. Apply outreach decay for stale sequences per salesMarketing.outreachDecayDays\n\nReport all signal detections, score changes, and MQL promotions.`,
    context: JSON.stringify({
      instruction: "Read config.json verticals section for signal sources and scoring matrices. Use salesMarketing section for MQL thresholds. Focus on signal sources scheduled for wednesday_1000.",
      configPath: "claude-runner/config.json",
      configKeys: ["verticals", "salesMarketing"],
      focusSchedule: "wednesday_1000"
    })
  }
}];

